class Solution:
    def strongPasswordChecker(self, password):
        s = password
        n = len(s)
        has_lower = any(c.islower() for c in s)
        has_upper = any(c.isupper() for c in s)
        has_digit = any(c.isdigit() for c in s)
        missing = (0 if has_lower else 1) + (0 if has_upper else 1) + (0 if has_digit else 1)
        # collect run lengths of >= 3 identical chars
        runs = []
        i = 0
        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            if j - i >= 3:
                runs.append(j - i)
            i = j
        if n < 6:
            return max(6 - n, missing)
        if n <= 20:
            replace = sum(r // 3 for r in runs)
            return max(replace, missing)
        # n > 20: deletions required
        delete = n - 20
        rem = delete
        # use deletions to reduce replacements: prefer runs with len%3==0, then ==1
        from collections import defaultdict
        buckets = defaultdict(list)
        for r in runs:
            buckets[r % 3].append(r)
        runs2 = list(runs)
        # pass for mod 0: one deletion saves a replacement
        def apply_deletions(runs_list):
            arr = sorted(runs_list, key=lambda r: r % 3)
            return arr
        # simulate deletions over a mutable list
        rl = list(runs)
        d = delete
        # phase: spend on mod==0 (cost 1), then mod==1 (cost 2), then mod==2 (cost 3)
        for need in (1, 2):
            for idx in range(len(rl)):
                if d <= 0:
                    break
                if rl[idx] >= 3 and rl[idx] % 3 == (0 if need == 1 else 1):
                    take = min(d, need)
                    if take == need:
                        rl[idx] -= need
                        d -= need
            if d <= 0:
                break
        # phase: spend remaining deletions, each removes one char (every 3 removed saves a replace)
        idx = 0
        while d > 0 and idx < len(rl):
            if rl[idx] >= 3:
                take = min(d, rl[idx] - 2)
                rl[idx] -= take
                d -= take
            idx += 1
        replace = sum(r // 3 for r in rl)
        return delete + max(replace, missing)

