class Solution:
    def strongPasswordChecker(self, password):
        s = password
        n = len(s)
        has_lower = any('a' <= c <= 'z' for c in s)
        has_upper = any('A' <= c <= 'Z' for c in s)
        has_digit = any('0' <= c <= '9' for c in s)
        missing = 3 - (has_lower + has_upper + has_digit)
        runs = []
        i = 0
        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            if j - i >= 3:
                runs.append(j - i)
            i = j
        replace = sum(r // 3 for r in runs)
        if n < 6:
            return max(6 - n, missing)
        if n <= 20:
            return max(replace, missing)
        delete = n - 20
        d = delete
        for r in range(len(runs)):
            if d <= 0:
                break
            if runs[r] % 3 == 0:
                runs[r] -= 1
                d -= 1
        for r in range(len(runs)):
            if d <= 0:
                break
            if runs[r] > 2 and runs[r] % 3 == 1:
                take = min(d, 2)
                runs[r] -= take
                d -= take
        for r in range(len(runs)):
            if d <= 0:
                break
            if runs[r] > 2:
                take = min(d, runs[r] - 2)
                runs[r] -= take
                d -= take
        replace = sum(r // 3 for r in runs)
        return delete + max(replace, missing)

