var strongPasswordChecker = function(password) {
    const s = password;
    const n = s.length;
    let hasLower = false, hasUpper = false, hasDigit = false;
    for (const c of s) {
        if (c >= 'a' && c <= 'z') hasLower = true;
        else if (c >= 'A' && c <= 'Z') hasUpper = true;
        else if (c >= '0' && c <= '9') hasDigit = true;
    }
    const missing = 3 - ((hasLower ? 1 : 0) + (hasUpper ? 1 : 0) + (hasDigit ? 1 : 0));
    const runs = [];
    let i = 0;
    while (i < n) {
        let j = i;
        while (j < n && s[j] === s[i]) j++;
        if (j - i >= 3) runs.push(j - i);
        i = j;
    }
    let replace = runs.reduce((a, r) => a + Math.floor(r / 3), 0);
    if (n < 6) return Math.max(6 - n, missing);
    if (n <= 20) return Math.max(replace, missing);
    const del = n - 20;
    let d = del;
    for (let r = 0; r < runs.length && d > 0; r++) {
        if (runs[r] % 3 === 0) { runs[r] -= 1; d -= 1; }
    }
    for (let r = 0; r < runs.length && d > 0; r++) {
        if (runs[r] > 2 && runs[r] % 3 === 1) { const take = Math.min(d, 2); runs[r] -= take; d -= take; }
    }
    for (let r = 0; r < runs.length && d > 0; r++) {
        if (runs[r] > 2) { const take = Math.min(d, runs[r] - 2); runs[r] -= take; d -= take; }
    }
    replace = runs.reduce((a, r) => a + Math.floor(r / 3), 0);
    return del + Math.max(replace, missing);
};
